-- First, let's see all duplicates with their IDs
SELECT id, projectId, entityType, prefix, currentNumber FROM idSequences WHERE entityType IN ('task', 'requirement', 'issue') ORDER BY entityType, currentNumber;

-- Delete the lower currentNumber entries (keep the higher ones)
DELETE FROM idSequences WHERE entityType = 'task' AND currentNumber = 2;
DELETE FROM idSequences WHERE entityType = 'requirement' AND currentNumber = 0 LIMIT 1;
DELETE FROM idSequences WHERE entityType = 'issue' AND currentNumber = 0 LIMIT 1;

-- Verify cleanup
SELECT entityType, prefix, currentNumber FROM idSequences WHERE entityType IN ('task', 'requirement', 'issue');

